public class Main {
    sealed interface Animal permits Dog, Cat {}
    record Dog(String name) implements Animal {}
    record Cat(String name, boolean indoor) implements Animal {}

    static String describe(Object obj) {
        if (obj instanceof Dog d) {
            return "犬: " + d.name();
        } else if (obj instanceof Cat c && c.indoor()) {
            return "室内猫: " + c.name();
        } else if (obj instanceof Cat c) {
            return "外猫: " + c.name();
        }
        return "不明";
    }

    public static void main(String[] args) {
        System.out.println(describe(new Cat("タマ", true)));
        System.out.println(describe(new Dog("ポチ")));
    }
}

